	// This is not lossless
	inline half_float qlog_to_half(uint32_t qlog, uint32_t bits)
	{
		assert((bits >= 7U) && (bits <= 16U));
		assert(qlog < (1U << bits));

		int C = qlog << (16 - bits);
		return astc_helpers::qlog16_to_half(C);
	}

